// ================================================================
// WF-ANALYZER — thay hoan toan pf_analyzer.py (co SESSION/static data)
// ================================================================
// Doc pfsense.log -> engine nguong -> DEDUPE qua static data (nhu _banned
// cua analyzer) -> tra ve: audit (moi detection) + new_bans (IP MOI ghi file).
//
// $getWorkflowStaticData('global') = "session" ben vung giua cac lan chay,
// thay cho bien _banned song suot doi process cua analyzer.py.

const content = $('Extract Text').first().json.data || '';
const rawLines = content.split('\n').filter(l => l.trim());

const INTERNAL_NETS = ['192.168.10.','192.168.11.','192.168.12.','192.168.20.'];
const IGNORE_PREFIXES = ['169.254.','224.','239.','255.','0.','127.'];
const IGNORE_EXACT = ['192.168.183.1','192.168.10.1'];
const THRESHOLDS = {
  BRUTE_FORCE:{count:5,window:60}, PORT_SCAN:{distinctPorts:15,window:10},
  CONN_FLOOD:{count:100,window:10}, DDOS_SPREAD:{distinctIps:20,window:10},
};
const isInternal = ip => ip && INTERNAL_NETS.some(n=>ip.startsWith(n));
const shouldIgnore = ip => !ip || IGNORE_EXACT.includes(ip) || IGNORE_PREFIXES.some(p=>ip.startsWith(p));
const pickAttacker = (s,d) => (s&&!isInternal(s))?s:((d&&!isInternal(d))?d:(s||d));

const RE_ANY_IP=/\b(\d{1,3}(?:\.\d{1,3}){3})\b/g;
const RE_TCP=/,tcp,\d+,(\d{1,3}(?:\.\d{1,3}){3}),(\d{1,3}(?:\.\d{1,3}){3}),(\d+),(\d+),[^,]*,([A-Z]*)/;
const RE_SSH=/Failed password for (?:invalid user )?(\S+) from (\d{1,3}(?:\.\d{1,3}){3}) port (\d+)/;

function extractSignal(raw){
  const low=raw.toLowerCase();
  const a=raw.match(RE_SSH);
  if(a){const ip=a[2]; if(shouldIgnore(ip)||isInternal(ip))return null; return {kind:'auth_fail',src_ip:ip,dst_port:22};}
  if(low.includes('filterlog')&&(low.includes(',block,')||low.includes(',pass,'))){
    const ips=[...raw.matchAll(RE_ANY_IP)].map(m=>m[1]);
    if(ips.length<2)return null;
    const att=pickAttacker(ips[0],ips[1]);
    if(isInternal(att)||shouldIgnore(att))return null;
    const t=raw.match(RE_TCP); let dp=null,fl=null;
    if(t){dp=parseInt(t[4],10);fl=t[5];}
    return {kind:fl==='S'?'syn':'fw_block',src_ip:att,dst_port:dp};
  }
  return null;
}
const nowFrom=l=>{const tb=l.indexOf('\t'); if(tb<0)return Date.now()/1000; const t=Date.parse(l.slice(0,tb)); return isNaN(t)?Date.now()/1000:t/1000;};

// Gom event theo IP
const events={};
for(const line of rawLines){
  const tb=line.indexOf('\t'); const raw=tb>=0?line.slice(tb+1):line; const now=nowFrom(line);
  const sig=extractSignal(raw); if(!sig)continue;
  (events[sig.src_ip]=events[sig.src_ip]||[]).push({ts:now,port:sig.dst_port,kind:sig.kind});
}
const nowMax=rawLines.length?nowFrom(rawLines[rawLines.length-1]):Date.now()/1000;
const cntW=(l,w,k,p)=>l.filter(e=>(nowMax-e.ts)<=w&&(!k||e.kind===k)&&(p===undefined||e.port===p)).length;
const dportsW=(l,w,k)=>{const s=new Set();l.forEach(e=>{if((nowMax-e.ts)<=w&&(!k||e.kind===k)&&e.port!=null)s.add(e.port);});return s.size;};

// Xet nguong
const detections=[];
for(const ip of Object.keys(events)){
  const l=events[ip]; let f=null;
  const af=l.filter(e=>e.kind==='auth_fail');
  if(af.length){const bp={};af.forEach(e=>bp[e.port]=(bp[e.port]||0)+1);
    for(const p of Object.keys(bp)){const c=cntW(l,THRESHOLDS.BRUTE_FORCE.window,'auth_fail',Number(p));if(c>=THRESHOLDS.BRUTE_FORCE.count){f={type:'BRUTE_FORCE',metric:c};break;}}}
  if(!f){const t=cntW(l,THRESHOLDS.CONN_FLOOD.window);if(t>=THRESHOLDS.CONN_FLOOD.count)f={type:'CONN_FLOOD',metric:t};}
  if(!f){const d=dportsW(l,THRESHOLDS.PORT_SCAN.window,'fw_block');if(d>=THRESHOLDS.PORT_SCAN.distinctPorts)f={type:'PORT_SCAN',metric:d};}
  if(!f){const d=dportsW(l,THRESHOLDS.PORT_SCAN.window,'syn');if(d>=THRESHOLDS.PORT_SCAN.distinctPorts)f={type:'PORT_SCAN',metric:d};}
  if(f)detections.push({src_ip:ip,event_type:f.type,metric:f.metric});
}

// ===== DEDUPE qua SESSION (static data) — phan cot loi giong _banned =====
const staticData = $getWorkflowStaticData('global');
staticData.banned = staticData.banned || {PORT_SCAN:[],BRUTE_FORCE:[],CONN_FLOOD:[]};

const BAN_MAP={PORT_SCAN:'BanIP_Scanport.txt',BRUTE_FORCE:'BanIP_Bruteforce.txt',CONN_FLOOD:'BanIP_DDOS.txt'};
const newBans=[];
for(const d of detections){
  const list = staticData.banned[d.event_type] || (staticData.banned[d.event_type]=[]);
  if(!list.includes(d.src_ip)){            // chi ghi IP CHUA tung ban
    list.push(d.src_ip);
    newBans.push({...d, ban_file:BAN_MAP[d.event_type]});
  }
}

// ===== Gom theo file de ghi (moi loai 1 item, gom cac IP moi) =====
const byFile={};
for(const b of newBans){
  (byFile[b.ban_file]=byFile[b.ban_file]||[]).push(b);
}

const out=[];
for(const file of Object.keys(byFile)){
  const items=byFile[file];
  out.push({ json:{
    ban_file: file,
    ips: items.map(i=>i.src_ip),
    // noi dung ghi vao file ban (moi IP 1 dong)
    ban_content: items.map(i=>i.src_ip).join('\n') + '\n',
    // noi dung audit (JSON tung dong) ghi vao analyzer_events.log
    audit_content: items.map(i=>JSON.stringify({
      ts:new Date().toISOString(), src_ip:i.src_ip,
      event_type:i.event_type, metric:i.metric
    })).join('\n') + '\n',
    count: items.length,
  }});
}

// Neu khong co ban moi -> tra ve item danh dau (de nhanh IF loc bo)
if(out.length===0){
  return [{ json:{ no_new_ban:true, scanned:rawLines.length,
                   total_detections:detections.length } }];
}
return out;
